import React, { useState, useEffect } from 'react';
import { ShoppingCart, Package, Tag, Store, Plus, Check, Loader2 } from 'lucide-react';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const PanelCliente = () => {
    const [ofertas, setOfertas] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const { cart, addToCart, count, total, clearCart } = useCart();

    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                setOfertas(data);
            } catch (err) {
                setError("No se pudieron sincronizar las ofertas de la nube.");
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    const handleCheckout = async () => {
        if (cart.length === 0) return;
        const session = JSON.parse(localStorage.getItem('user-session'));
        if (!session) return alert("Inicia sesión para finalizar");

        try {
            const pedidoData = {
                clienteId: session.userId || session.user?.id,
                puntoEntrega: { direccion: "Retiro en local" },
                items: cart.map(item => ({
                    producto: item.producto,
                    precio: item.precioNuevo,
                    cantidad: item.cantidad,
                    local: item.local?._id || item.local
                }))
            };
            await api.crearPedido(pedidoData);
            alert("¡Pedido realizado con éxito!");
            clearCart();
        } catch (err) {
            alert("Error: " + err.message);
        }
    };

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p style={{marginTop: '15px'}}>Sincronizando con la nube...</p>
        </div>
    );

    return (
        <div style={container}>
            {/* HEADER ESTILO VENDEDOR */}
            <div style={sectionHeader}>
                <div>
                    <h2 style={{ color: '#1e293b', margin: 0, fontSize: '1.8rem' }}>Tienda de Ofertas</h2>
                    <p style={{ color: '#64748b', margin: 0 }}>Productos disponibles en la nube</p>
                </div>
                
                <div style={cartSummaryCard}>
                    <div style={{display: 'flex', alignItems: 'center', gap: '10px'}}>
                        <ShoppingCart color="#e67e22" />
                        <div style={{textAlign: 'left'}}>
                            <span style={badgeCount}>{count} items</span>
                            <div style={totalAmountHeader}>${total.toLocaleString()}</div>
                        </div>
                    </div>
                    {count > 0 && (
                        <button onClick={handleCheckout} style={btnCheckout}>
                            Confirmar Compra
                        </button>
                    )}
                </div>
            </div>

            {/* GRID DE PRODUCTOS */}
            <div style={grid}>
                {ofertas.map((oferta) => (
                    <div key={oferta._id} style={cardProducto}>
                        <div style={imageContainer}>
                            {oferta.url ? (
                                <img src={oferta.url} alt={oferta.producto} style={imgStyle} />
                            ) : (
                                <Package size={40} color="#cbd5e1" />
                            )}
                            <div style={categoryTag}>{oferta.categoria}</div>
                        </div>

                        <div style={productBody}>
                            <h3 style={productTitle}>{oferta.producto}</h3>
                            <div style={localRow}>
                                <Store size={14} color="#94a3b8" />
                                <span style={localName}>{oferta.local?.nombre || 'Sucursal General'}</span>
                            </div>

                            <div style={priceRow}>
                                <div style={{display: 'flex', flexDirection: 'column'}}>
                                    <span style={oldPrice}>${oferta.precioViejo}</span>
                                    <span style={newPrice}>${oferta.precioNuevo}</span>
                                </div>
                                <div style={stockInfo(oferta.stock)}>
                                    {oferta.stock > 0 ? `${oferta.stock} disp.` : 'Agotado'}
                                </div>
                            </div>

                            <button 
                                onClick={() => addToCart(oferta)}
                                disabled={oferta.stock <= 0}
                                style={oferta.stock > 0 ? btnAdd : btnDisabled}
                            >
                                {oferta.stock > 0 ? (
                                    <><Plus size={18} /> Agregar al carrito</>
                                ) : 'Sin Stock'}
                            </button>
                        </div>
                    </div>
                ))}
            </div>
            
            {ofertas.length === 0 && (
                <div style={emptyState}>
                    <Tag size={40} color="#cbd5e1" />
                    <p>No hay ofertas publicadas actualmente.</p>
                </div>
            )}
        </div>
    );
};

// --- ESTILOS (Sincronizados con VistaPedidosVendedor) ---
const container = { maxWidth: '1100px', margin: '0 auto', padding: '30px 20px' };
const sectionHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px', flexWrap: 'wrap', gap: '20px' };
const cartSummaryCard = { background: 'white', padding: '15px 25px', borderRadius: '16px', border: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', gap: '25px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const badgeCount = { background: '#ffedd5', color: '#e67e22', padding: '2px 8px', borderRadius: '10px', fontSize: '0.75rem', fontWeight: 'bold' };
const totalAmountHeader = { fontSize: '1.4rem', fontWeight: '900', color: '#1e293b' };
const btnCheckout = { background: '#22c55e', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold', transition: '0.2s' };

const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '25px' };
const cardProducto = { background: 'white', borderRadius: '20px', overflow: 'hidden', border: '1px solid #e2e8f0', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.05)', display: 'flex', flexDirection: 'column' };
const imageContainer = { height: '200px', background: '#f8fafc', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const categoryTag = { position: 'absolute', top: '12px', right: '12px', background: 'rgba(255,255,255,0.9)', padding: '4px 10px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 'bold', color: '#64748b', textTransform: 'uppercase' };

const productBody = { padding: '20px', display: 'flex', flexDirection: 'column', flex: 1 };
const productTitle = { margin: '0 0 8px 0', fontSize: '1.15rem', color: '#1e293b', fontWeight: 'bold', textTransform: 'capitalize' };
const localRow = { display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '15px' };
const localName = { color: '#94a3b8', fontSize: '0.85rem' };

const priceRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '20px' };
const oldPrice = { color: '#94a3b8', textDecoration: 'line-through', fontSize: '0.85rem' };
const newPrice = { color: '#ef4444', fontSize: '1.6rem', fontWeight: '900', lineHeight: 1 };
const stockInfo = (stock) => ({ fontSize: '0.75rem', color: stock > 5 ? '#22c55e' : '#e67e22', background: stock > 5 ? '#f0fdf4' : '#fff7ed', padding: '4px 8px', borderRadius: '6px', fontWeight: '600' });

const btnAdd = { background: '#1e293b', color: 'white', border: 'none', padding: '12px', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontWeight: 'bold', transition: '0.2s' };
const btnDisabled = { ...btnAdd, background: '#f1f5f9', color: '#94a3b8', cursor: 'not-allowed' };

const emptyState = { textAlign: 'center', padding: '60px', color: '#94a3b8', background: '#f8fafc', borderRadius: '24px', border: '2px dashed #e2e8f0', gridColumn: '1 / -1' };
const centerState = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '60vh', color: '#64748b' };

export default PanelCliente;
